var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CULTIST_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"저희 마을에 오신 걸 환영합니다.","JPN":"我が村へようこそお越しくださいました。","ENG":"Welcome to our humble village.","TWN":"歡迎光臨我們的村莊。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CULTIST_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"여행자 분들이신 것 같은데 어쩐 일로 이렇게 숲속 깊은 마을까지 찾아오셨나요?","JPN":"旅の方のようですが、このような森の奥の村に何かご用でも？","ENG":"What brings you travelers to a village so deep within the forest?","TWN":"你們應該是旅客吧？怎麼會跑到這森林深處裡的村莊呢？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"여행자? 어이 총각 우리 복장이 안 보여?","JPN":"旅？　あのさ、お兄さん。この服装見てわからない？","ENG":"Travelers? Hey mister, can't you tell who we are by our uniforms?","TWN":"旅客？喂，小夥子，你沒看到我們這身裝扮嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CULTIST_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"물론이죠. 저희 마을은 세계수님의 가호 아래 매년 번창하고 있는 걸요.","JPN":"もちろんです。我が村は世界樹様の加護で毎年栄えておりますから。","ENG":"Well of course I do. Every year, our village grows stronger thanks to the protection of the World Tree.","TWN":"當然，我們的村莊在世界樹的守護之下，每年都相當繁榮呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CULTIST_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"그래<color=#ff3636>서 주차</color>는 선불<color=#ff3636>로 하시</color>겠어요, 후불<color=#ff3636>로 하시</color>겠<b>어</b>요?","JPN":"それ<color=#ff3636>で駐車代</color>は先払<color=#ff3636>いにしま</color>すか、後払い<color=#ff3636>にし</color>ま<b>す</b>か？","ENG":"So, wi<color=#ff3636>ll you pa</color>y upfront or la<color=#ff3636>ter for you</color>r parki<color=#ff3636>ng sp</color>a<b>ce</b>?","TWN":"請問，<color=#ff3636>停車費的部分</color>是要<color=#ff3636>先繳</color>嗎？還<color=#ff3636>是要後</color>繳<b>呢</b>？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"어쩔래, 꺽다리? 내 눈에는 천국 직행 티켓이 필요할 것 같은데.","JPN":"どうする？　のっぽ。あたしの目には天国直行チケットが必要そうだけど。","ENG":"What's it gonna be, Long Legs? I'm thinking we all give them a one-way ticket to Heaven.","TWN":"高個子，怎麼辦？感覺好像需要送他搭地獄直達列車欸？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"내가 이야기해보지.","JPN":"私が話してみよう。","ENG":"I will talk to them.","TWN":"我來跟他說說看。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"여행을 하다 잠시 길을 잘못 들었습니다.","JPN":"旅の途中で少し道に迷ってしまいました。","ENG":"We lost our way while travelling.","TWN":"我們在旅途中不小心走錯路，"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L13_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"말씀대로 이렇게 번창한 마을이라면, 하루 정도 묵을 곳이 있겠군요.","JPN":"おっしゃるとおり、こんなに豊かな村なら、一晩泊まれるところはあるでしょう。","ENG":"But, if your village is as prosperous as you claim, surely there must be somewhere we can spend the night?","TWN":"若照你所言，這個村莊相當繁榮，那應該有可以歇一晚的地方吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CULTIST_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"아, 잘됐습니다, 손님. 때마침 마을 축제 기간이라 먹거리가 풍족합니다.","JPN":"お客さん、いい時にきましたね。ちょうど村祭りの期間ですので、食べ物がたくさんありますよ。","ENG":"Oh, you're just in luck! We are currently having a festival, so there's plenty to eat!","TWN":"喔！你們來得正好，現在剛好是慶典時期，有很多好吃的呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CULTIST_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"두 사람<color=#ff3636> 먹을 정도</color>라면 충분하겠죠. <color=#ff3636>A코스</color>로 해드<b>릴</b>까요?","JPN":"お二人<color=#ff3636>で食べるくらい</color>なら十分でしょう。<color=#ff3636>Aコース</color>にしま<b>しょう</b>か？","ENG":"I'm sur<color=#ff3636>e we have enough</color> for two mor<color=#ff3636>e. Will it be t</color>he A c<b>ou</b>rse?","TWN":"應該是<color=#ff3636>夠你們二</color>個人吃的。請問<color=#ff3636>A餐</color>好<b>嗎</b>？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"부탁하겠습니다.","JPN":"お願いします。","ENG":"We appreciate your hospitality.","TWN":"好的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CULTIST_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"자, 그럼 따라오시죠.","JPN":"では、こちらにどうぞ。","ENG":"All right then. Follow me, please.","TWN":"那請跟我來。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CULTIST_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"작은 마을이지<color=#ff3636>만…… 볼</color> 거리는 <color=#ff3636>충분할</color> 겁니다.","JPN":"小さな村です<color=#ff3636>が……見</color>どころは<color=#ff3636>たくさんある</color>と思いますよ。","ENG":"It's a sm<color=#ff3636>all village bu</color>t... there's mu<color=#ff3636>ch to see he</color>re.","TWN":"別看我們村莊<color=#ff3636>小……小的</color>，有很多值得<color=#ff3636>欣賞</color>的地方呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"꺽다리 진짜 괜찮은 거 맞아?","JPN":"のっぽ、本当に大丈夫なの？","ENG":"Hey, Long Legs! You sure we'll be okay?","TWN":"高個子，你確定沒問題嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"걱정마라 신디. 광인에게는 광인의 논리가 있다.","JPN":"心配するな、シンディ。狂人には狂人の理屈がある。","ENG":"Do not be concerned, Cindy. Maniacs think in their own logical way.","TWN":"沒事的，辛蒂，我自有辦法。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"용케도 그들을 따라갔군요. 그래서 당신은 그 마을에서 뭘 봤죠?","JPN":"よくついて行きましたね。それで、あなたはあの村で何を見たのですか？","ENG":"So you actually followed them. What did you see within the village?","TWN":"結果你們就這樣跟去嗎？所以你看到什麼？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"의외로 별건 없었어.","JPN":"意外と大したことはなかったよ。","ENG":"There wasn't much, to be honest.","TWN":"完全出乎意料，什麼也沒看到。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"어떤 놈들은 춤을 추며 노래 부르고, 어떤 놈들은 미친 듯이 땅바닥에 무언가를 그리고 있고, 또 어떤 놈들은 구석에서 요리를 준비하고 있고.","JPN":"あるやつは踊りながら歌って、あるやつは地面に狂ったように何かを描いて、またあるやつは隅っこで料理の準備をして。","ENG":"Some were singing and dancing. Others were drawing something in dirt. And one was preparing food in the corner.","TWN":"有些人在唱歌跳舞，有些人好像發瘋一樣，不知道在地上畫什麼，有些人在一旁準備食物。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"멀리서 봤으면, 진짜 마을 축제인 줄 알겠더라.","JPN":"遠くから見れば、本当に村祭りに見えたかもね。","ENG":"Anyone would've guessed it was a festival from far away.","TWN":"遠看的話，就好像正常的慶典一樣。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_HATE"}}}},{"id":"L30_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"가까이서 보면?","JPN":"近くで見ると？","ENG":"But up close?","TWN":"那近看呢？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_HATE"}}}},{"id":"L31_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"녀석들이 먹으라고 내준 수프에 왕꿈틀이가 가득했어.","JPN":"やつらが食べろって出したスープに大王ミミズがいっぱい入ってた。","ENG":"The soup these people were eating was full of those big wigglers.","TWN":"他們端給我們喝的湯裡全都是大蚯蚓。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"클로디아가 그걸 봤어야 쇼크 먹고 주방에 안 들어갈 텐데.","JPN":"クラウディアが見ればショックでキッチンに入らなくなるのになあ。","ENG":"I should've shown that to Claudia, then she’d never go back in the kitchen.","TWN":"克勞迪婭看到的話，應該會嚇到不敢進廚房吧？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"손님 대접이 극진한 마을이로군요.","JPN":"手厚いもてなしをしてくれる村なのですね。","ENG":"So the village itself was hospitable.","TWN":"還真是盛情款待客人的村莊呢。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_LAUGH"}}}},{"id":"L34_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"하지만 짐작가는 바가 있습니다. 그 왕꿈틀이가 사교도를 조종하고 있는 거겠죠.","JPN":"ですが思い当たるところはあります。その大王ミミズが邪教徒を操っているのでしょう。","ENG":"But I suspect that it was those big wigglers that were controlling the cultists?","TWN":"不過可想而知，是大蚯蚓在控制邪教徒吧？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"헤엥……. 아는 게 많아서 좋으시겠어.","JPN":"へえ……物知りで良かったね。","ENG":"Heh... It must be nice to be a big know-it-all.","TWN":"嘿嘿……你真聰明。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"하지만 이상한 대목이로군요.","JPN":"ですが、おかしな一節ですね。","ENG":"But what a strange occurrence...","TWN":"不過這段有點奇怪。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그 왕꿈틀이는 사교도들을 조종하여 뭘 하려고 했던 걸까요?","JPN":"その大王ミミズは邪教徒を操って何をしようとしたのでしょうか？","ENG":"What were these big wigglers trying to achieve by controlling the cultists?","TWN":"大蚯蚓控制邪教徒是想做什麼？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"뭔 소리래, 언니 아마추어야?","JPN":"何言ってるんだよ？　お姉さん、プロじゃないの？","ENG":"Seriously? You can't connect the dots?","TWN":"姊姊你在說什麼？你是外行人嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"사교도들 축제는 대부분 의식이나 주술과 관련되어 있잖아. 뭐 대충 그런 거겠지.","JPN":"邪教徒の祭りはほとんどが儀式とか呪術と関係してるじゃん。まあ、大体そんなもんでしょ。","ENG":"A cultist festival is usually associated with some form of black magic or ritual. So it's most likely one of the two, if not both.","TWN":"邪教徒的慶典，通常不都跟什麼儀式或咒術有關嗎？不就那些？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"의외로 감이 나쁘지 않으시군요. 시스터 루퍼.","JPN":"意外と勘がいいのですね。シスタールーパー。","ENG":"I guess you are not as dull as you look, Sister Looper.","TWN":"洛珀姊妹，你很聰明呢。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"하지만 제가 말씀드린 건 시스터 넬슨이 납치된 사건을 포함한 이야기입니다.","JPN":"ですが、私が言いたかったのはシスターネルソンが拉致された事件も含めての話です。","ENG":"However, I was actually implying how this connects with Sister Nelson's kidnapping.","TWN":"但我指的是，包括尼爾森姊妹遭綁架的事在內。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"종교 공동체라고는 하지만 그 정도 규모라면…….","JPN":"宗教共同体といえど、その程度の規模なら……","ENG":"Even though it is a religious community... Just the size alone...","TWN":"雖說是宗教共同體，但這樣的規模……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"시스터, 마을에 젊은 여성이나 아이가 얼마나 있었죠?","JPN":"シスター、村に若い女性や子どもは何人くらいいましたか？","ENG":"How many women and children did you see in the village, Sister?","TWN":"洛珀姊妹，村裡有多少年輕女性和小孩？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L46_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"뭐야, 당신?","JPN":"何？　あんた。","ENG":"Huh? What are you?","TWN":"你是怎樣？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"왜 그러시죠. 시스터?","JPN":"どうしましたか？　シスター。","ENG":"What is wrong, Sister?","TWN":"什麼怎樣？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"꺽다리도 방금 당신이랑 똑같은 소리를 했어.","JPN":"のっぽも今のあんたと同じこと言ってた。","ENG":"Long Legs said the same thing to me.","TWN":"高個子剛才也跟你說過一樣的話。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"신디. 지금까지의 조사로 알아낸 사실이 있다.","JPN":"シンディ。今までの調査でわかったことがある。","ENG":"Cindy. There is something I have discovered thus far.","TWN":"辛蒂，就目前為止的調查來看，我發現一件事。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"뭔데? 클로디아보다 요리 못하는 놈들이 있다는 거?","JPN":"何？　クラウディアより料理下手なやつがいるってこと？","ENG":"What? That there's someone who's a worse cook than Claudia?","TWN":"什麼？有人比克勞迪婭更不會做菜嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"그보다 중요한 문제다.","JPN":"それより重要な問題だ。","ENG":"It is more important than that.","TWN":"比這件事還嚴重。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"마을에 진입하기 전 철퇴 용병단의 시체는 우릴 적대시했지.","JPN":"村に入る前、鉄槌傭兵団の死体は私たちを敵視していた。","ENG":"Before entering this village, the Mace Mercenary corpses were hostile to us.","TWN":"在我們進到村莊以前，鐵鎚傭兵團的活屍視我們為敵人對吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"하지만 저들은 우릴 공격하지 않아. 일개미처럼 자기 일에만 몰두하고 있어.","JPN":"だが、あの者たちは攻撃してこない。働きアリのように自分たちの仕事に専念している。","ENG":"However, \\"they\\" are not attacking us. They are preoccupied with their work, just like worker ants.","TWN":"但他們並未攻擊我們，而是像工蟻一樣埋頭苦幹。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"즉, 마을에 뿌리내린 침식체는 저들에게 역할을 분배하고 있다는 거다.","JPN":"つまり、村に根付いた侵食体は村人に役割分担を与えているということだ。","ENG":"Thus, the C.O. that rooted down in this village is assigning roles to each of them.","TWN":"意思就是，在村裡扎根的侵蝕體會分配工作給他們。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"녀석들이 무언가 준비하고 있다는 거야?","JPN":"やつらが何かを準備してるってこと？","ENG":"You mean they're preparing for something?","TWN":"他們在準備什麼嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"그리고 또 하나.","JPN":"そしてもう一つ。","ENG":"And one more thing.","TWN":"還有另一件很詭異的事，"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"이 마을에는 이상할 정도로 젊은 여성과 아이가 눈에 띄지 않아.","JPN":"この村には怪しいほどに若い女性と子どもが見当たらない。","ENG":"Oddly enough, there are no women and children to be found here.","TWN":"我完全沒看到村裡有年輕女性和孩子。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"얼레? 그러고 보니 죄다 두건 눌러쓴 칙칙한 총각 놈들뿐이잖아?","JPN":"あれ？　そういえば、みんな頭巾をかぶったお兄さんばっかりだね。","ENG":"Huh? Now that you mention it, all I see are dirty men in bandanas...!","TWN":"喔喔？這麼說來，都是些戴著頭巾的小夥子呢？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"예로부터 젊은 여성과 아이는 인신공양의 희생양이 되곤 했지.","JPN":"昔から若い女性と子どもは人身御供にされてきた。","ENG":"Since ancient times, young women and children have been offered as human sacrifices.","TWN":"自古以來，年輕女性和孩子經常被當作是活祭的祭物。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"어쩌면…… 클로디아가 납치당한 것도 이와 관련이 있을지도 모르겠군.","JPN":"もしかすると……クラウディアが拉致されたのもこれと関係があるのかもしれない。","ENG":"Perhaps... This has some connection to Claudia's kidnapping as well.","TWN":"很有可能……克勞迪婭就是因為這樣才被綁架的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"그건 클로디아가 녀석들의 제물이 될지도 모른다는 거야?","JPN":"それって、クラウディアがやつらの生贄になるかもしれないってこと？","ENG":"Do you mean Claudia is gonna be their next sacrifice?","TWN":"意思是，克勞迪婭很可能是他們的祭物？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"어디까지나 가정일 뿐이다.","JPN":"どこまでも仮説に過ぎないが。","ENG":"It is a possibility.","TWN":"這只是我的假設而已。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"우선 마을에서 여성과 아이들을 수용할 만한 공간을 찾아야한다.","JPN":"まず、村で女性と子供たちを収容できそうな場所を探すべきだ。","ENG":"First of all, we must locate where they would keep all the women and children in the village.","TWN":"先找找村裡有沒有可以容納女性和小孩的地方吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"어쩌면 클로디아는 그곳에……","JPN":"もしかするとクラウディアはそこに……","ENG":"Claudia might be th─","TWN":"克勞迪婭可能就在那裡……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"OCTOPUS3_VATICAN_NULL_NULL","text":{"KOREA":"<color=#ff3636>성찬</color>을 준비하<color=#ff3636>라. 새로운 날</color>이 당도하<b>리</b>니.","JPN":"<color=#ff3636>聖餐</color>を用意し<color=#ff3636>ろ。新しい日</color>が到来<b>す</b>る。","ENG":"Prepare <color=#ff3636>the fea</color>st. A new da<color=#ff3636>wn is</color> com<b>in</b>g.\xA0","TWN":"預備<color=#ff3636>盛宴</color><color=#ff3636>吧。新天</color>已來<b>到</b>。\xA0"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OCTOPUS3_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"뭐야? 이 왕꿈틀이는 엄청나게 크잖아?","JPN":"何？　この大王ミミズ、めっちゃ大きいんだけど。","ENG":"Huh? That big wiggler's huge!","TWN":"這是怎樣？大蚯蚓也未免太大隻！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"이 침식체는…… ","JPN":"この侵食体は…… ","ENG":"This C.O. is...","TWN":"這侵蝕體是…… "},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"잔해? ","JPN":"残骸？ ","ENG":"The Remains?","TWN":"殘骸？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"그렇다면 이 마을은 설마 학회의……?","JPN":"だとすると、この村はまさか学会の……？","ENG":"Then, did Society...?","TWN":"該不會這個村莊是學會……？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"신디, 이 침식체가 마을에 뿌리내려 시체들을 조종하는 녀석일 거다.","JPN":"シンディ、この侵食体が村に根付いて死体を操っているやつだろう。","ENG":"Cindy, this must be the C.O. that has rooted down in this village and is controlling the corpses.","TWN":"辛蒂，應該就是這個侵蝕體在控制屍體的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L30_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"아무래도 우리의 의도를 눈치채고 선수를 치려는 모양이군.","JPN":"どうやら私たちの意図に気付いて先手を打つつもりのようだ。","ENG":"Perhaps it has already noticed our intentions and are trying to beat us to our objective.","TWN":"它很可能是發現到我們的意圖，於是打算先下手為強。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"그래? 이 녀석만 잡으면 끝이다 이거지?","JPN":"そうなの？　じゃあ、こいつをやっつければ終わりってことだよね？","ENG":"Yeah? So all we have to do is chop that thing up and game over, right?","TWN":"是嗎？意思是只要解決它就結束囉？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"주여, 어째서 이토록 추악한 악행을 그저 방관만 하시나이까.","JPN":"主よ、どうしてこのように醜悪な悪行をただ傍観なさっているのですか。","ENG":"Lord, how could You just sit back and watch such a heinous and evil deed?","TWN":"天主，您為何無視如此醜陋的惡行呢？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"좋아! 요단강 익스프레스, 시동 걸었어!","JPN":"よし！　ヨルダン川エクスプレス、エンジンかけた！","ENG":"All right! All aboard the Styx Express!","TWN":"很好！送你直達地獄！啟動！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_CHAINSAW_ATTACK_SMALL"}]`);export{e as default};